import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FiSun, FiMoon, FiHome, FiUser, FiBriefcase, FiGithub, FiAward, FiMail, FiMenu, FiX } from 'react-icons/fi';
import { useTheme } from '../ThemeContext';

const links = [
    { href: '#home',         icon: FiHome,      label: 'Home'         },
    { href: '#about',        icon: FiUser,      label: 'About'        },
    { href: '#projects',     icon: FiBriefcase, label: 'Projects'     },
    { href: '#github',       icon: FiGithub,    label: 'GitHub'       },
    { href: '#certificates', icon: FiAward,     label: 'Certificates' },
    { href: '#contact',      icon: FiMail,      label: 'Contact'      },
];

const scrollTo = (id, cb) => {
    const el = document.getElementById(id.replace('#',''));
    if (el) window.scrollTo({ top: el.offsetTop - 72, behavior: 'smooth' });
    if (cb) cb();
};

const Navbar = () => {
    const { isDark, theme, toggleTheme } = useTheme();
    const [active, setActive] = useState('home');
    const [open, setOpen]     = useState(false);

    useEffect(() => {
        const ids = ['home','about','projects','github','certificates','contact'];
        const onScroll = () => {
            ids.forEach(id => {
                const el = document.getElementById(id);
                if (el && window.scrollY >= el.offsetTop - 150) setActive(id);
            });
        };
        window.addEventListener('scroll', onScroll, { passive: true });
        return () => window.removeEventListener('scroll', onScroll);
    }, []);

    return (
        <>
            {/* ── Desktop: floating pill ── */}
            <motion.div
                initial={{ y: -60, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                transition={{ duration: 0.55, ease: [0.16,1,0.3,1] }}
                className="nav-desk-pill"
                style={{
                    position: 'fixed', top: 14, left: '50%',
                    transform: 'translateX(-50%)',
                    zIndex: 1000,
                    display: 'flex', alignItems: 'center', gap: 2,
                    background: isDark ? 'rgba(14,14,14,0.92)' : 'rgba(240,240,235,0.92)',
                    backdropFilter: 'blur(32px)',
                    border: `1px solid ${theme.border}`,
                    borderRadius: 100,
                    padding: '5px 6px',
                    boxShadow: isDark
                        ? '0 8px 40px rgba(0,0,0,0.7)'
                        : '0 8px 40px rgba(0,0,0,0.12)',
                }}
            >
                {/* Logo */}
                <a href="#home" onClick={e => { e.preventDefault(); scrollTo('#home'); }}
                    style={{ display:'flex', alignItems:'center', gap:7, padding:'4px 10px 4px 4px', textDecoration:'none' }}>
                    <div style={{
                        width:28, height:28, borderRadius:'50%',
                        background:'#facc15',
                        display:'flex', alignItems:'center', justifyContent:'center',
                        flexShrink:0,
                    }}>
                        <span style={{ fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:13, color:'#000', lineHeight:1 }}>B</span>
                    </div>
                    <span style={{ fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:13, color: theme.textPrimary, letterSpacing:'-0.3px', whiteSpace:'nowrap' }}>BARA</span>
                </a>

                {/* Divider */}
                <div style={{ width:1, height:18, background: theme.border, margin:'0 2px', flexShrink:0 }} />

                {/* Nav icons */}
                {links.map(l => {
                    const isAct = active === l.href.replace('#','');
                    const Icon  = l.icon;
                    return (
                        <a key={l.href} href={l.href}
                            onClick={e => { e.preventDefault(); scrollTo(l.href); }}
                            title={l.label}
                            style={{
                                width:36, height:36, borderRadius:100,
                                display:'flex', alignItems:'center', justifyContent:'center',
                                background: isAct
                                    ? (isDark ? 'rgba(250,204,21,0.15)' : 'rgba(202,138,4,0.12)')
                                    : 'transparent',
                                border: `1px solid ${isAct ? 'rgba(250,204,21,0.4)' : 'transparent'}`,
                                color: isAct ? '#facc15' : theme.textMuted,
                                textDecoration:'none', cursor:'pointer',
                                transition:'all 0.2s ease',
                                flexShrink:0,
                            }}
                            onMouseEnter={e => { if(!isAct){ e.currentTarget.style.background='rgba(255,255,255,0.05)'; e.currentTarget.style.color=theme.textPrimary; } }}
                            onMouseLeave={e => { if(!isAct){ e.currentTarget.style.background='transparent'; e.currentTarget.style.color=theme.textMuted; } }}
                        >
                            <Icon size={15} />
                        </a>
                    );
                })}
            </motion.div>

            {/* ── Theme toggle (right, outside pill) ── */}
            <motion.button
                initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.4 }}
                onClick={toggleTheme}
                aria-label="Toggle theme"
                className="nav-desk-pill"
                style={{
                    position:'fixed', top:14, right:16, zIndex:1000,
                    width:40, height:40, borderRadius:100,
                    background: isDark ? 'rgba(14,14,14,0.92)' : 'rgba(240,240,235,0.92)',
                    backdropFilter:'blur(32px)',
                    border:`1px solid ${theme.border}`,
                    display:'flex', alignItems:'center', justifyContent:'center',
                    color: theme.textMuted, cursor:'pointer',
                    boxShadow: isDark ? '0 4px 20px rgba(0,0,0,0.6)' : '0 4px 20px rgba(0,0,0,0.1)',
                    transition:'all 0.2s',
                }}
                onMouseEnter={e => { e.currentTarget.style.color='#facc15'; e.currentTarget.style.borderColor='rgba(250,204,21,0.35)'; }}
                onMouseLeave={e => { e.currentTarget.style.color=theme.textMuted; e.currentTarget.style.borderColor=theme.border; }}
            >
                {isDark ? <FiSun size={15}/> : <FiMoon size={15}/>}
            </motion.button>

            {/* ── Mobile header ── */}
            <div className="nav-mob-bar" style={{
                position:'fixed', top:0, left:0, right:0, height:56, zIndex:1000,
                display:'flex', alignItems:'center', justifyContent:'space-between',
                padding:'0 16px',
                background: isDark ? 'rgba(10,10,10,0.95)' : 'rgba(245,245,240,0.95)',
                backdropFilter:'blur(24px)',
                borderBottom:`1px solid ${theme.border}`,
            }}>
                <a href="#home" onClick={e => { e.preventDefault(); scrollTo('#home'); }}
                    style={{ display:'flex', alignItems:'center', gap:7, textDecoration:'none' }}>
                    <div style={{ width:26, height:26, borderRadius:'50%', background:'#facc15', display:'flex', alignItems:'center', justifyContent:'center' }}>
                        <span style={{ fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:12, color:'#000' }}>B</span>
                    </div>
                    <span style={{ fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:14, color:theme.textPrimary, letterSpacing:'-0.3px' }}>BARA</span>
                </a>
                <div style={{ display:'flex', gap:8 }}>
                    <button onClick={toggleTheme} aria-label="Toggle theme" style={{ width:34, height:34, borderRadius:9, background:'transparent', border:`1px solid ${theme.border}`, display:'flex', alignItems:'center', justifyContent:'center', color:theme.textMuted, cursor:'pointer' }}>
                        {isDark ? <FiSun size={13}/> : <FiMoon size={13}/>}
                    </button>
                    <button onClick={() => setOpen(o=>!o)} aria-label="Menu" style={{ width:34, height:34, borderRadius:9, background:'transparent', border:`1px solid ${theme.border}`, display:'flex', alignItems:'center', justifyContent:'center', color:theme.textPrimary, cursor:'pointer' }}>
                        {open ? <FiX size={15}/> : <FiMenu size={15}/>}
                    </button>
                </div>
            </div>

            {/* Mobile drawer */}
            <AnimatePresence>
                {open && (
                    <motion.div initial={{ opacity:0, y:-8 }} animate={{ opacity:1, y:0 }} exit={{ opacity:0, y:-8 }}
                        transition={{ duration:0.2 }}
                        style={{
                            position:'fixed', top:56, left:0, right:0, zIndex:999,
                            background: isDark ? 'rgba(10,10,10,0.98)' : 'rgba(245,245,240,0.98)',
                            backdropFilter:'blur(24px)',
                            borderBottom:`1px solid ${theme.border}`,
                            padding:'12px 16px 16px',
                        }}
                    >
                        {links.map(l => {
                            const isAct = active === l.href.replace('#','');
                            const Icon  = l.icon;
                            return (
                                <a key={l.href} href={l.href}
                                    onClick={e => { e.preventDefault(); scrollTo(l.href, () => setOpen(false)); }}
                                    style={{
                                        display:'flex', alignItems:'center', gap:12,
                                        padding:'11px 14px', borderRadius:12, marginBottom:4,
                                        fontSize:14, fontWeight: isAct ? 700 : 500,
                                        fontFamily:'Inter,sans-serif',
                                        color: isAct ? '#000' : theme.textSecondary,
                                        background: isAct ? '#facc15' : 'transparent',
                                        border:`1px solid ${isAct ? '#facc15' : 'transparent'}`,
                                        textDecoration:'none',
                                    }}
                                >
                                    <Icon size={15}/> {l.label}
                                </a>
                            );
                        })}
                    </motion.div>
                )}
            </AnimatePresence>

            <style>{`
                .nav-desk-pill { display:flex!important; }
                .nav-mob-bar   { display:none!important; }
                @media(max-width:767px){
                    .nav-desk-pill { display:none!important; }
                    .nav-mob-bar   { display:flex!important; }
                }
            `}</style>
        </>
    );
};

export default Navbar;