import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FiChevronUp, FiGithub, FiLinkedin, FiMail, FiArrowRight } from 'react-icons/fi';
import { useTheme } from '../ThemeContext';

const navLinks = [
    { href:'#home',         label:'Home'         },
    { href:'#about',        label:'About'        },
    { href:'#projects',     label:'Projects'     },
    { href:'#certificates', label:'Certificates' },
    { href:'#contact',      label:'Contact'      },
];

const Footer = () => {
    const { theme, isDark } = useTheme();
    const [show, setShow] = useState(false);

    useEffect(() => {
        const fn = () => setShow(window.scrollY > 400);
        window.addEventListener('scroll', fn, { passive:true });
        return () => window.removeEventListener('scroll', fn);
    }, []);

    const scrollTo = id => {
        const el = document.querySelector(id);
        if (el) el.scrollIntoView({ behavior:'smooth' });
    };

    return (
        <>
            {/* CTA Card - "Scroll Now / Thank Yourself Later" */}
            <div style={{ padding:'0 clamp(16px,4vw,40px)', marginBottom:48 }}>
                <motion.div
                    initial={{ opacity:0, y:30 }} whileInView={{ opacity:1, y:0 }}
                    transition={{ duration:0.6, ease:[0.16,1,0.3,1] }} viewport={{ once:true }}
                    style={{
                        maxWidth:460, margin:'0 auto',
                        background:'linear-gradient(135deg, #facc15 0%, #fbbf24 100%)',
                        borderRadius:24, padding:'clamp(28px,4vw,40px)',
                        textAlign:'center',
                        boxShadow:'0 20px 60px rgba(250,204,21,0.25)',
                    }}
                >
                    <h3 style={{
                        fontFamily:'Syne,sans-serif', fontWeight:800,
                        fontSize:'clamp(22px,3.5vw,30px)',
                        color:'#000', letterSpacing:'-0.5px', marginBottom:4,
                    }}>Scroll Now</h3>
                    <p style={{
                        fontFamily:'Syne,sans-serif', fontWeight:700,
                        fontSize:'clamp(14px,2vw,18px)',
                        color:'rgba(0,0,0,0.65)', marginBottom:20,
                    }}>Thank Yourself Later</p>
                    <button
                        onClick={() => window.scrollTo({ top:0, behavior:'smooth' })}
                        style={{
                            display:'inline-flex', alignItems:'center', gap:7,
                            padding:'10px 28px', borderRadius:100,
                            background:'rgba(0,0,0,0.15)', border:'none',
                            fontFamily:'Syne,sans-serif', fontWeight:800,
                            fontSize:13, color:'#000', cursor:'pointer',
                            letterSpacing:1.5, textTransform:'uppercase',
                            transition:'all 0.2s',
                        }}
                        onMouseEnter={e => { e.currentTarget.style.background='rgba(0,0,0,0.25)'; }}
                        onMouseLeave={e => { e.currentTarget.style.background='rgba(0,0,0,0.15)'; }}
                    >
                        SCROLL ↓
                    </button>
                </motion.div>
            </div>

            {/* Footer */}
            <footer style={{
                borderTop:`1px solid ${theme.border}`,
                background: isDark ? 'rgba(5,5,5,0.8)' : 'rgba(240,240,235,0.8)',
                padding:'clamp(40px,6vw,60px) clamp(16px,4vw,40px)',
            }}>
                <div style={{ maxWidth:1200, margin:'0 auto' }}>

                    {/* 3-column grid */}
                    <div style={{
                        display:'grid',
                        gridTemplateColumns:'repeat(auto-fit, minmax(200px,1fr))',
                        gap:'clamp(32px,4vw,48px)',
                        marginBottom:40,
                    }}>
                        {/* Col 1: Brand */}
                        <div>
                            <a href="#home" onClick={e => { e.preventDefault(); window.scrollTo({ top:0, behavior:'smooth' }); }}
                                style={{ textDecoration:'none', display:'inline-block', marginBottom:12 }}>
                                <span style={{
                                    fontFamily:'Syne,sans-serif', fontWeight:800,
                                    fontSize:22, color:'#facc15', letterSpacing:'-0.5px',
                                }}>BARA</span>
                            </a>
                            <p style={{
                                fontFamily:'Inter,sans-serif', fontSize:13.5,
                                lineHeight:1.7, color:theme.textSecondary,
                                marginBottom:20, maxWidth:220,
                            }}>
                                Building amazing web experiences with modern technologies.
                            </p>
                            {/* Social icons */}
                            <div style={{ display:'flex', gap:10, marginBottom:20 }}>
                                {[
                                    { href:'https://github.com/BekaGensss',  icon:<FiGithub size={14}/>,   label:'GitHub'   },
                                    { href:'https://id.linkedin.com/in/bara-kusuma-707067294', icon:<FiLinkedin size={14}/>, label:'LinkedIn' },
                                    { href:'mailto:barakusuma911@gmail.com', icon:<FiMail size={14}/>,     label:'Email'    },
                                ].map(s => (
                                    <a key={s.label} href={s.href}
                                        target={s.href.startsWith('http') ? '_blank' : undefined}
                                        rel="noopener noreferrer" aria-label={s.label}
                                        style={{
                                            width:34, height:34, borderRadius:9,
                                            background: isDark ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.05)',
                                            border:`1px solid ${theme.border}`,
                                            display:'flex', alignItems:'center', justifyContent:'center',
                                            color:theme.textMuted, textDecoration:'none', transition:'all 0.2s',
                                        }}
                                        onMouseEnter={e => { e.currentTarget.style.borderColor='#facc15'; e.currentTarget.style.color='#facc15'; }}
                                        onMouseLeave={e => { e.currentTarget.style.borderColor=theme.border; e.currentTarget.style.color=theme.textMuted; }}
                                    >{s.icon}</a>
                                ))}
                            </div>
                            <p style={{ fontFamily:'Inter,sans-serif', fontSize:11.5, color:theme.textMuted }}>
                                © {new Date().getFullYear()} All Rights Reserved
                            </p>
                        </div>

                        {/* Col 2: Navigate */}
                        <div>
                            <div style={{ fontFamily:'Syne,sans-serif', fontWeight:700, fontSize:11, color:'#facc15', letterSpacing:2.5, textTransform:'uppercase', marginBottom:20 }}>
                                // NAVIGATE
                            </div>
                            <nav style={{ display:'flex', flexDirection:'column', gap:8 }}>
                                {navLinks.map(l => (
                                    <a key={l.href} href={l.href}
                                        onClick={e => { e.preventDefault(); scrollTo(l.href); }}
                                        style={{
                                            display:'flex', alignItems:'center', gap:7,
                                            fontFamily:'Inter,sans-serif', fontSize:13.5, fontWeight:500,
                                            color:theme.textSecondary, textDecoration:'none',
                                            transition:'all 0.2s',
                                        }}
                                        onMouseEnter={e => { e.currentTarget.style.color='#facc15'; e.currentTarget.style.paddingLeft='4px'; }}
                                        onMouseLeave={e => { e.currentTarget.style.color=theme.textSecondary; e.currentTarget.style.paddingLeft='0'; }}
                                    >
                                        <FiArrowRight size={11} /> {l.label}
                                    </a>
                                ))}
                            </nav>
                        </div>

                        {/* Col 3: Info */}
                        <div>
                            <div style={{ fontFamily:'Syne,sans-serif', fontWeight:700, fontSize:11, color:'#facc15', letterSpacing:2.5, textTransform:'uppercase', marginBottom:20 }}>
                                // INFO
                            </div>
                            <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
                                {[
                                    { label:'Location',     val:'Indonesia'          },
                                    { label:'Experience',   val:'3+ years'           },
                                    { label:'Availability', val:'Open to work ✅'    },
                                    { label:'',             val:'&lt;/&gt; Full Stack Developer', code:true },
                                ].map((item,i) => (
                                    <div key={i} style={{ fontFamily:'Inter,sans-serif', fontSize:13 }}>
                                        {item.label && (
                                            <span style={{ fontWeight:600, color:theme.textPrimary }}>{item.label}: </span>
                                        )}
                                        {item.code ? (
                                            <span style={{ fontFamily:'monospace', fontSize:12, color:'#facc15' }}>
                                                {'</>'}  Full Stack Developer
                                            </span>
                                        ) : (
                                            <span style={{ color:theme.textSecondary }}>{item.val}</span>
                                        )}
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>

                    {/* Bottom bar */}
                    <div style={{
                        paddingTop:20, borderTop:`1px solid ${theme.border}`,
                        display:'flex', flexWrap:'wrap',
                        justifyContent:'space-between', alignItems:'center', gap:12,
                    }}>
                        <span style={{ fontFamily:'Inter,sans-serif', fontSize:11.5, color:theme.textMuted }}>
                            Designed with minimalism in mind
                        </span>
                        <span style={{ fontFamily:'Inter,sans-serif', fontSize:11.5, color:theme.textMuted }}>
                            Made with ❤️ using React.js
                        </span>
                    </div>
                </div>
            </footer>

            {/* Scroll to top */}
            <AnimatePresence>
                {show && (
                    <motion.button
                        key="stb"
                        initial={{ scale:0, opacity:0 }} animate={{ scale:1, opacity:1 }} exit={{ scale:0, opacity:0 }}
                        onClick={() => window.scrollTo({ top:0, behavior:'smooth' })}
                        aria-label="Ke atas"
                        style={{
                            position:'fixed', bottom:20, right:18,
                            width:40, height:40, borderRadius:12, border:'none',
                            background: isDark ? '#ffffff' : '#0a0a0a',
                            color: isDark ? '#000' : '#fff',
                            display:'flex', alignItems:'center', justifyContent:'center',
                            cursor:'pointer', zIndex:50,
                            boxShadow:'0 6px 20px rgba(0,0,0,0.3)',
                        }}
                        whileHover={{ y:-3, boxShadow:'0 10px 28px rgba(0,0,0,0.4)' }}
                        whileTap={{ scale:0.9 }}
                    >
                        <FiChevronUp size={18} />
                    </motion.button>
                )}
            </AnimatePresence>
        </>
    );
};

export default Footer;