import React, { useState, useEffect } from 'react';
import { ThemeProvider, useTheme } from './ThemeContext';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import About from './components/About';
import Projects from './components/Projects';
import GitHubRepos from './components/GitHubRepos';
import Certificates from './components/Certificates';
import Contact from './components/Contact';
import Footer from './components/Footer';

/* ─── Minimalist Loader ─── */
const Loader = ({ isDark }) => {
    const [progress, setProgress] = useState(0);

    useEffect(() => {
        const interval = setInterval(() => {
            setProgress(p => {
                if (p >= 100) { clearInterval(interval); return 100; }
                const step = p < 70 ? Math.random() * 15 + 6 : Math.random() * 7 + 2;
                return Math.min(p + step, 100);
            });
        }, 60);
        return () => clearInterval(interval);
    }, []);

    const bg  = isDark ? '#0a0a0a' : '#f5f5f0';
    const fg  = isDark ? '#ffffff' : '#0a0a0a';
    const dim = isDark ? 'rgba(255,255,255,0.15)' : 'rgba(0,0,0,0.15)';
    const bar = isDark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.07)';

    return (
        <div style={{
            position: 'fixed', inset: 0, zIndex: 9999,
            background: bg,
            display: 'flex', flexDirection: 'column',
            alignItems: 'center', justifyContent: 'center',
        }}>
            <div style={{
                fontFamily: 'Syne, sans-serif', fontWeight: 800,
                fontSize: 'clamp(36px, 7vw, 72px)',
                color: fg, letterSpacing: '-2px', lineHeight: 1,
                marginBottom: 40,
            }}>
                BARA<span style={{ color: '#facc15' }}>.</span>
            </div>
            <div style={{ width: 120, height: 2, background: bar, borderRadius: 2, overflow: 'hidden' }}>
                <div style={{
                    height: '100%', width: `${progress}%`,
                    background: '#facc15',
                    transition: 'width 0.1s ease',
                }} />
            </div>
            <div style={{
                marginTop: 14, fontFamily: 'Inter, sans-serif',
                fontSize: 9, fontWeight: 700, color: dim,
                letterSpacing: 3, textTransform: 'uppercase',
            }}>
                Loading
            </div>
        </div>
    );
};

const AppContent = () => {
    const { isDark, theme } = useTheme();
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const t = setTimeout(() => setLoading(false), 1600);
        return () => clearTimeout(t);
    }, []);

    return (
        <>
            <div style={{
                opacity: loading ? 1 : 0,
                pointerEvents: loading ? 'all' : 'none',
                transition: 'opacity 0.6s ease',
                position: 'fixed', inset: 0, zIndex: 9999,
            }}>
                <Loader isDark={isDark} />
            </div>

            <div style={{
                minHeight: '100vh',
                backgroundColor: theme.bg,
                transition: 'background-color 0.4s ease',
                display: 'flex', flexDirection: 'column',
            }}>
                <Navbar />
                <main style={{ flex: 1 }}>
                    <Hero />
                    <About />
                    <Projects />
                    <GitHubRepos />
                    <Certificates />
                    <Contact />
                </main>
                <Footer />
            </div>
        </>
    );
};

const App = () => (
    <ThemeProvider><AppContent /></ThemeProvider>
);

export default App;